import XCTest
@testable import BotaplataApp

final class TradingChartMapperTests: XCTestCase {
    func testValidationAndMapping() throws { let envelope = try fixture(); let chart = try RealSessionChartMapper.map(envelope: envelope); XCTAssertEqual(chart.candles.map(\.id), ["c1", "c2"]); XCTAssertEqual(chart.markers[0].kind, .buy); XCTAssertEqual(chart.markers[1].kind, .partialSell); XCTAssertEqual(chart.levels.breakEvenPrice, Decimal(string: "74.4")) }
    func testInvalidCandlesAreFiltered() throws { var dto = try XCTUnwrap(fixture().data); let bad = RealChartCandleDTO(id: "bad", openTime: Date(timeIntervalSince1970: 2), closeTime: Date(timeIntervalSince1970: 1), isClosed: true, open: DecimalString(1), high: DecimalString(1), low: DecimalString(1), close: DecimalString(1), volume: nil, vwap: nil, ema200: nil, bollingerUpper: nil, bollingerMiddle: nil, bollingerLower: nil); dto = RealSessionChartDTO(sessionID: dto.sessionID, symbol: dto.symbol, displaySymbol: dto.displaySymbol, quoteAsset: dto.quoteAsset, range: dto.range, timeframe: dto.timeframe, generatedAt: dto.generatedAt, dataSource: dto.dataSource, isComplete: dto.isComplete, hasMore: dto.hasMore, nextBefore: dto.nextBefore, series: dto.series + [bad], markers: dto.markers, levels: dto.levels); let chart = try RealSessionChartMapper.map(envelope: APIEnvelope(ok: true, data: dto, error: nil, meta: APIMeta(requestID: "r", serverTime: nil))); XCTAssertEqual(chart.candles.count, 2) }
    private func fixture() throws -> APIEnvelope<RealSessionChartDTO> { let url = URL(fileURLWithPath: #filePath).deletingLastPathComponent().appendingPathComponent("Fixtures/MobileV1/real_session_chart_6h.json"); return try JSONCoding.decoder.decode(APIEnvelope<RealSessionChartDTO>.self, from: Data(contentsOf: url)) }
}
